    10→var (
    11→	// ErrInvalidScope is returned when the scope is not valid for the action
    12→	ErrInvalidScopeTplt = "invalid scope: {{.Public.Scope}}, for action: {{.Public.Action}}, expected prefixes are {{.Public.ValidScopesFormat}}"
    13→	ErrBaseInvalidScope = errutil.BadRequest("permreg.invalid-scope").MustTemplate(ErrInvalidScopeTplt, errutil.WithPublic(ErrInvalidScopeTplt))
    14→
    15→	ErrUnknownActionTplt = "unknown action: {{.Public.Action}}, was not found in the list of valid actions"
    16→	ErrBaseUnknownAction = errutil.BadRequest("permreg.unknown-action").MustTemplate(ErrUnknownActionTplt, errutil.WithPublic(ErrUnknownActionTplt))
    17→
    18→	ErrBaseUnknownKind = errutil.BadRequest("permreg.unknown-kind").MustTemplate("unknown kind: {{.Public.Kind}}")
    19→)
    20→
    21→func ErrInvalidScope(scope string, action string, validScopePrefixes PrefixSet) error {
    22→	if len(validScopePrefixes) == 0 {
    23→		return ErrBaseInvalidScope.Build(errutil.TemplateData{Public: map[string]any{"Scope": scope, "Action": action, "ValidScopesFormat": "[none]"}})
    24→	}
    25→	formats := generateValidScopeFormats(validScopePrefixes)
    26→	return ErrBaseInvalidScope.Build(errutil.TemplateData{Public: map[string]any{"Scope": scope, "Action": action, "ValidScopesFormat": formats}})
    27→}
    28→
    29→func ErrUnknownAction(action string) error {
    30→	return ErrBaseUnknownAction.Build(errutil.TemplateData{Public: map[string]any{"Action": action}})
    31→}
    32→
    33→func ErrUnknownKind(kind string) error {
    34→	return ErrBaseUnknownKind.Build(errutil.TemplateData{Public: map[string]any{"Kind": kind}})
    35→}
    36→
    37→func generateValidScopeFormats(acceptedScopePrefixes PrefixSet) []string {
    38→	if len(acceptedScopePrefixes) == 0 {
    39→		return []string{}
    40→	}
    41→	acceptedPrefixesList := make([]string, 0, 10)
    42→	acceptedPrefixesList = append(acceptedPrefixesList, "*")
    43→	for prefix := range acceptedScopePrefixes {
    44→		parts := strings.Split(prefix, ":")
    45→		// If the prefix has an attribute part add the intermediate format kind:*
    46→		if len(parts) > 2 {
    47→			acceptedPrefixesList = append(acceptedPrefixesList, parts[0]+":*")
    48→		}
    49→		// Add the most specific format kind:attribute:*
    50→		acceptedPrefixesList = append(acceptedPrefixesList, prefix+"*")
    51→	}
    52→	return acceptedPrefixesList
    53→}
    54→
    55→type PermissionRegistry interface {
    56→	RegisterPluginScope(scope string)
    57→	RegisterPermission(action, scope string) error
    58→	IsPermissionValid(action, scope string) error
    59→	GetScopePrefixes(action string) (PrefixSet, bool)
    60→}
    61→
    62→type PrefixSet map[string]bool
    63→
    64→var _ PermissionRegistry = &permissionRegistry{}
    65→
    66→type permissionRegistry struct {
    67→	actionScopePrefixes map[string]PrefixSet // TODO use thread safe map
    68→	kindScopePrefix     map[string]string
    69→	logger              log.Logger
    70→}
    71→
    72→func ProvidePermissionRegistry() PermissionRegistry {
    73→	return newPermissionRegistry()
    74→}
    75→
    76→func newPermissionRegistry() *permissionRegistry {
    77→	// defaultKindScopes maps the most specific accepted scope prefix for a given kind (folders, dashboards, etc)
    78→	defaultKindScopes := map[string]string{
    79→		"teams":               "teams:id:",
    80→		"users":               "users:id:",
    81→		"datasources":         "datasources:uid:",
    82→		"dashboards":          "dashboards:uid:",
    83→		"folders":             "folders:uid:",
    84→		"annotations":         "annotations:type:",
    85→		"orgs":                "orgs:id:",
    86→		"plugins":             "plugins:id:",
    87→		"provisioners":        "provisioners:",
    88→		"reports":             "reports:id:",
    89→		"permissions":         "permissions:type:",
    90→		"serviceaccounts":     "serviceaccounts:id:",
    91→		"settings":            "settings:",
    92→		"global.users":        "global.users:id:",
    93→		"roles":               "roles:uid:",
    94→		"services":            "services:",
    95→		"receivers":           "receivers:uid:",
    96→		"secret.securevalues": "secret.securevalues:uid:",
    97→		"secret.keepers":      "secret.keepers:uid:",
    98→	}
    99→	return &permissionRegistry{
   100→		actionScopePrefixes: make(map[string]PrefixSet, 200),
   101→		kindScopePrefix:     defaultKindScopes,
   102→		logger:              log.New("accesscontrol.permreg"),
   103→	}
   104→}
   105→
   106→func (pr *permissionRegistry) RegisterPluginScope(scope string) {
   107→	if scope == "" {
   108→		return
   109→	}
   110→
   111→	scopeParts := strings.Split(scope, ":")
   112→	kind := scopeParts[0]
   113→
   114→	// If the scope is already registered, return
   115→	if _, found := pr.kindScopePrefix[kind]; found {
   116→		return
   117→	}
   118→
   119→	// If the scope contains an attribute part, register the kind and attribute
   120→	if len(scopeParts) > 2 {
   121→		attr := scopeParts[1]
   122→		pr.kindScopePrefix[kind] = kind + ":" + attr + ":"
   123→		pr.logger.Debug("registered scope prefix", "kind", kind, "scope_prefix", kind+":"+attr+":")
   124→		return
   125→	}
   126→
   127→	pr.logger.Debug("registered scope prefix", "kind", kind, "scope_prefix", kind+":")
   128→	pr.kindScopePrefix[kind] = kind + ":"
   129→}
   130→
   131→func (pr *permissionRegistry) RegisterPermission(action, scope string) error {
   132→	if _, ok := pr.actionScopePrefixes[action]; !ok {
   133→		pr.actionScopePrefixes[action] = PrefixSet{}
   134→	}
   135→
   136→	if scope == "" {
   137→		// scopeless action
   138→		return nil
   139→	}
   140→
   141→	kind := strings.Split(scope, ":")[0]
   142→	scopePrefix, ok := pr.kindScopePrefix[kind]
   143→	if !ok {
   144→		pr.logger.Error("unknown kind: please update `kindScopePrefix` with the correct scope prefix", "kind", kind)
   145→		return ErrUnknownKind(kind)
   146→	}
   147→
   148→	// Add a new entry in case the scope is not empty
   149→	pr.actionScopePrefixes[action][scopePrefix] = true
   150→	return nil

